const data = $input.item.json;

function tryParseJson(value) {
  if (typeof value !== 'string') return value;

  const text = value.trim();
  if (!text.startsWith('{') && !text.startsWith('[')) return value;

  try {
    return JSON.parse(text);
  } catch {
    return value;
  }
}

function firstObject(...values) {
  for (const value of values) {
    if (value && typeof value === 'object' && !Array.isArray(value)) {
      return value;
    }
  }
  return {};
}

function asString(value) {
  return typeof value === 'string' ? value.trim() : '';
}

function asStringArray(value) {
  if (!Array.isArray(value)) return [];
  return value
    .map((item) => String(item ?? '').trim())
    .filter(Boolean);
}

function today() {
  return new Date().toISOString().slice(0, 10);
}

const root = tryParseJson(data.output ?? data.result ?? data.data ?? data);
const result = firstObject(root?.output, root?.result, root?.data, root);

const versiculoPrincipal = firstObject(result.versiculo_principal);
const versiculoApoio = firstObject(result.versiculo_apoio);
const metadata = firstObject(result.metadata);

const normalized = {
  text: asString(result.text) || asString(data.output) || '',
  title: asString(result.title),
  date: asString(result.date) || today(),
  versiculo_principal: {
    texto: asString(versiculoPrincipal.texto),
    referencia: asString(versiculoPrincipal.referencia),
  },
  versiculo_apoio: {
    texto: asString(versiculoApoio.texto),
    referencia: asString(versiculoApoio.referencia),
  },
  metadata: {
    autor: asString(metadata.autor) || 'Alex e Daniela Mantovani',
    tema: asString(metadata.tema),
    conceito_central: asString(metadata.conceito_central),
    palavras_chave: asStringArray(metadata.palavras_chave),
    relacionado_expressar: asString(metadata.relacionado_expressar),
  },
};

const warnings = [];

if (!normalized.text) warnings.push('Campo text ausente.');
if (!normalized.title) warnings.push('Campo title ausente.');
if (!normalized.versiculo_principal.referencia) warnings.push('Versículo principal sem referência.');
if (!normalized.versiculo_apoio.referencia) warnings.push('Versículo de apoio sem referência.');
if (normalized.text.length > 4000) warnings.push('Campo text excede 4000 caracteres.');

const parseOk =
  normalized.text.length > 0 &&
  normalized.title.length > 0 &&
  normalized.versiculo_principal.referencia.length > 0 &&
  normalized.versiculo_apoio.referencia.length > 0;

return {
  json: {
    ...normalized,
    parse_ok: parseOk,
    warnings,
    character_count: normalized.text.length,
    whatsapp_limit_ok: normalized.text.length <= 4000,
    erro: parseOk ? '' : 'Saída estruturada ausente, inválida ou incompleta no gerador de devocional.',
    raw: parseOk ? null : data,
  },
};

const data = $input.item.json;

function maybeParseJson(value) {
  if (typeof value !== 'string') return value;
  const text = value.trim();
  if (!text.startsWith('{') && !text.startsWith('[')) return value;

  try {
    return JSON.parse(text);
  } catch {
    return value;
  }
}

function pickObject(...values) {
  for (const value of values) {
    if (value && typeof value === 'object' && !Array.isArray(value)) {
      return value;
    }
  }
  return {};
}

function toString(value) {
  return typeof value === 'string' ? value.trim() : '';
}

function toStringArray(value) {
  if (!Array.isArray(value)) return [];
  return value
    .map((item) => String(item ?? '').trim())
    .filter(Boolean);
}

const root = maybeParseJson(data.output ?? data.result ?? data.data ?? data);
const result = pickObject(root?.output, root?.result, root?.data, root);

const analise = pickObject(result.analise);
const sugestao = pickObject(result.sugestao);

const normalized = {
  analise: {
    temas_abordados: toStringArray(analise.temas_abordados),
    versiculos_usados: toStringArray(analise.versiculos_usados),
    progressao: toString(analise.progressao),
    palavras_chave: toStringArray(analise.palavras_chave),
  },
  sugestao: {
    tema_sugerido: toString(sugestao.tema_sugerido),
    conceito_central: toString(sugestao.conceito_central),
    versiculos_sugeridos: toStringArray(sugestao.versiculos_sugeridos),
    direcionamento: toString(sugestao.direcionamento),
    contexto_historico: toString(sugestao.contexto_historico),
  },
};

const parseOk =
  normalized.analise.progressao.length > 0 &&
  normalized.sugestao.tema_sugerido.length > 0 &&
  normalized.sugestao.conceito_central.length > 0;

return {
  json: {
    ...normalized,
    parse_ok: parseOk,
    erro: parseOk ? '' : 'Saída estruturada ausente, inválida ou incompleta na classificação.',
    raw: parseOk ? null : data,
  },
};

